        "#dia-closet-v2-root .cv2-msg{padding:48px 24px;text-align:center;color:var(--ink2);font-weight:600;}",
        "#dia-closet-v2-root .cv2-cols{display:flex;gap:18px;align-items:flex-start;}",
        "#dia-closet-v2-root .cv2-col{flex:1;min-width:0;}",
        "#dia-closet-v2-root .cv2-colhead{font-weight:800;font-size:13px;text-transform:uppercase;letter-spacing:.05em;color:var(--ink);margin:0 2px 10px;display:flex;align-items:center;justify-content:space-between;gap:8px;}",
        "#dia-closet-v2-root .cv2-newlist-btn{font:700 10px/1 Inter,sans-serif;color:var(--dtr-primary,#2d9b77);background:var(--dtr-primary-bg,#eaf5f0);border:1px solid var(--dtr-primary-line,#cfe7df);border-radius:7px;padding:4px 8px;cursor:pointer;letter-spacing:.02em;text-transform:none;transition:background .12s,border-color .12s;flex-shrink:0;}",
        "#dia-closet-v2-root .cv2-newlist-btn:hover{background:#dcefe7;border-color:#a8d4c4;}",
        ".cv2-nl-overlay{position:fixed;inset:0;z-index:100000;background:rgba(30,50,42,.42);display:flex;align-items:center;justify-content:center;font-family:Inter,sans-serif;animation:cv2-nlin .14s ease;}",
        "@keyframes cv2-nlin{from{opacity:0}to{opacity:1}}",
        ".cv2-nl-modal{width:382px;max-width:calc(100vw - 32px);background:#fff;border-radius:16px;box-shadow:0 24px 60px -12px rgba(20,50,40,.5);padding:20px;box-sizing:border-box;}",
        ".cv2-nl-title{font:700 17px/1.2 Inter,sans-serif;color:var(--dtr-primary,#1c6b4e);margin-bottom:14px;}",
        ".cv2-nl-field{display:block;margin-bottom:13px;}",
        ".cv2-nl-field>span{display:block;font:600 11px/1.3 Inter,sans-serif;color:#5a6b64;text-transform:uppercase;letter-spacing:.04em;margin-bottom:5px;}",
        ".cv2-nl-field em{font-style:normal;color:#9bb3aa;text-transform:none;letter-spacing:0;}",
        ".cv2-nl-input{width:100%;box-sizing:border-box;font:500 13px/1.4 Inter,sans-serif;color:#1a2e28;background:#f6faf8;border:1.5px solid #dceee8;border-radius:9px;padding:9px 11px;outline:none;transition:border-color .15s,box-shadow .15s,background .15s;}",
        ".cv2-nl-input:focus{border-color:var(--dtr-primary,#2d9b77);background:#fff;box-shadow:0 0 0 3px rgba(45,155,119,.14);}",
        "textarea.cv2-nl-input{resize:vertical;min-height:42px;}",
        ".cv2-nl-seg{display:flex;gap:6px;}",
        ".cv2-nl-segbtn{flex:1;font:600 12px/1.2 Inter,sans-serif;color:#5a6b64;background:#f1f5f3;border:1.5px solid #e2ece8;border-radius:9px;padding:9px 8px;cursor:pointer;transition:all .12s;}",
        ".cv2-nl-segbtn.on{background:var(--dtr-primary-bg,#e6f5ee);border-color:var(--dtr-primary,#2d9b77);color:var(--dtr-primary,#1c6b4e);}",
