  const STATUS_OPTIONS = ['mailed', 'ghosted', 'incompatible WL', 'rejected'];

  function normalizeStatusKey(status) {
    return String(status || '').toLowerCase().trim();
  }

  function statusClassName(status) {
    return String(status || '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '') || 'custom';
  }

  function isBuiltInStatus(status) {
    const key = normalizeStatusKey(status);
    return STATUS_OPTIONS.some(opt => normalizeStatusKey(opt) === key);
  }

  function getStatusColor(status) {
    const key = normalizeStatusKey(status);
    const colors = getDIASection('statusColors', {});
    const saved = colors && typeof colors === 'object' ? colors[key] : '';
    return STATUS_COLOR_THEMES[saved] ? saved : 'yellow';
  }

  function setStatusColor(status, color) {
    const key = normalizeStatusKey(status);
    if (!key || !STATUS_COLOR_THEMES[color]) return;
    const colors = getDIASection('statusColors', {});
    colors[key] = color;
    setDIASection('statusColors', colors);
  }

  function deleteStatusColor(status) {
    const key = normalizeStatusKey(status);
    if (!key) return;
    const colors = getDIASection('statusColors', {});
    if (colors && typeof colors === 'object') {
      delete colors[key];
      setDIASection('statusColors', colors);
    }
  }

  function statusVisualClassName(status) {
    if (!status) return '';
    if (isBuiltInStatus(status)) return 'dia-status-' + statusClassName(status);
    return 'dia-status-tone-' + getStatusColor(status);
  }

  function statusRowClassName(status) {
    const visual = statusVisualClassName(status);
    return visual ? 'dia-row-' + visual.replace(/^dia-status-/, '') : '';
  }

  function getStatusOptions(extraStatuses) {
    const custom = Array.isArray(extraStatuses)
      ? extraStatuses
      : getDIASection('customStatuses', []);

    const removed = getDIASection('removedStatuses', [])
      .map(opt => String(opt).toLowerCase().trim());

    const seen = new Set();

    const all = STATUS_OPTIONS.concat(custom).filter(status => {
      const key = String(status || '').toLowerCase().trim();
      if (!key || removed.includes(key) || seen.has(key)) return false;
      seen.add(key);
      return true;
    });

    const order = getStatusOrder().map(s => String(s).toLowerCase().trim());
    if (!order.length) return all;

    const ordered = [];
    const remaining = [...all];
    order.forEach(key => {
      const idx = remaining.findIndex(s => String(s).toLowerCase().trim() === key);
      if (idx !== -1) ordered.push(remaining.splice(idx, 1)[0]);
    });
    return [...ordered, ...remaining];
  }

  function getStatusOrder() {
    return getDIASection('statusOrder', []);
  }

  function saveStatusOrder(order) {
    setDIASection('statusOrder', order);

    writeJSON(STATUS_ORDER_KEY, order);
  }

  function rememberCustomStatus(status, color) {
    const trimmed = String(status || '').trim();

    if (!trimmed) return;

    const builtIn = isBuiltInStatus(trimmed);
    const custom = getDIASection('customStatuses', []);

    if (!builtIn && !custom.some(opt => String(opt).toLowerCase() === trimmed.toLowerCase())) {
      custom.push(trimmed);
      custom.sort((a, b) => String(a).localeCompare(String(b)));
      setDIASection('customStatuses', custom);
    }

    if (!builtIn) {
      const resolvedColor = STATUS_COLOR_THEMES[color] ? color : getStatusColor(trimmed);

      if (STATUS_COLOR_THEMES[color]) {
        setStatusColor(trimmed, color);
      } else {
        const existing = getDIASection('statusColors', {})[normalizeStatusKey(trimmed)];
        setStatusColor(trimmed, STATUS_COLOR_THEMES[existing] ? existing : 'yellow');
      }
    }

    const removed = getDIASection('removedStatuses', [])
      .filter(opt => String(opt).toLowerCase() !== trimmed.toLowerCase());

    setDIASection('removedStatuses', removed);
  }

  function deleteCustomStatus(status) {
    const trimmed = String(status || '').trim();

    if (!trimmed) return;

    const custom = getDIASection('customStatuses', [])
      .filter(opt => String(opt).toLowerCase() !== trimmed.toLowerCase());

    const removed = getDIASection('removedStatuses', []);

    if (!removed.some(opt => String(opt).toLowerCase() === trimmed.toLowerCase())) {
      removed.push(trimmed);
    }

    deleteStatusColor(trimmed);
    setDIASection('customStatuses', custom);
    setDIASection('removedStatuses', removed);
  }

  function markLinkVisited(href) {
    if (!href) return;
    const visited = readJSON(VISITED_LINKS_KEY, {});
    visited[href] = Date.now();
    const keys = Object.keys(visited);
    if (keys.length > 2000) keys.slice(0, keys.length - 2000).forEach(k => delete visited[k]);
    writeJSON(VISITED_LINKS_KEY, visited);

    try { localStorage.setItem(VISITED_LINKS_KEY, JSON.stringify(visited)); } catch (_) {}
  }

  function isLinkVisited(href) {
    if (!href) return false;
    const visited = readJSON(VISITED_LINKS_KEY, {});
    return !!visited[href];
  }

  function clearLinkVisited(href) {
    if (!href) return;
    const visited = readJSON(VISITED_LINKS_KEY, {});
    if (!visited[href]) return;
    delete visited[href];
    writeJSON(VISITED_LINKS_KEY, visited);
    try { localStorage.setItem(VISITED_LINKS_KEY, JSON.stringify(visited)); } catch (_) {}
  }

  function seenCheckHtml(href) {
    if (!isLinkVisited(href)) return '';
    return `<button class="dia-seen-checkmark" type="button" data-seen-href="${safeText(href)}" title="Hold 3 seconds to mark unseen" aria-label="Hold 3 seconds to mark unseen">✓</button>`;
  }

  function saveBatch(batch) {
    GM_setValue(STORE_KEY, JSON.stringify({ savedAt: Date.now(), items: batch }));
  }

  function loadBatch() {
    try {
      const raw = GM_getValue(STORE_KEY, null);
      if (!raw) return null;
      const parsed = JSON.parse(raw);

      if (Date.now() - parsed.savedAt > 7 * 24 * 60 * 60 * 1000) return null;
      return parsed.items;
    } catch (_) {
      return null;
    }
  }

  const LAST_UPDATED_KEY = 'neo_dti_last_updated';
  function diaImportState() {
    try {
      const raw = GM_getValue(STORE_KEY, null);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (Date.now() - parsed.savedAt > 7 * 24 * 60 * 60 * 1000) return null;
      const count = Object.keys(parsed.items || {}).length;
      if (!count) return null;
      return { count, savedAt: parsed.savedAt || null, lastUpdated: GM_getValue(LAST_UPDATED_KEY, null) || parsed.savedAt || null };
    } catch (_) { return null; }
  }
  function diaTouchImport() { try { GM_setValue(LAST_UPDATED_KEY, Date.now()); } catch (_) {} }
