            const allItems = [...(bundle.owns || []), ...(bundle.wants || [])];
            const matches = allItems.filter(item => String(item?.itemId || '') === currentItemId);
            if (!matches.length) return null;
            const ownerSource = matches.find(item => item.ownerName || item.ownerHref || item.listHref) || allItems.find(item => item.ownerName || item.ownerHref || item.listHref) || {};
            const ownerName = String(ownerSource.ownerName || ownerSource.traderName || bundle.ownerName || bundle.traderName || 'Unknown trader').trim() || 'Unknown trader';
            const ownerHref = String(ownerSource.listHref || ownerSource.ownerHref || bundle.listHref || bundle.ownerHref || '').trim();
            return { bundleId: bundle.id, ownerName, ownerHref, matchCount: matches.length };
