        const applyPreviewPrefs = () => {
          const colorSelect = previewBody.querySelector('select[name="preview[color_id]"]');
          const speciesSelect = previewBody.querySelector('select[name="preview[species_id]"]');

          if (!colorSelect || !speciesSelect) return false;

          let changed = false;

          if (savedPreview.colorId && colorSelect.value !== savedPreview.colorId) {
            colorSelect.value = savedPreview.colorId;
            changed = true;
          }

          if (savedPreview.speciesId && speciesSelect.value !== savedPreview.speciesId) {
            speciesSelect.value = savedPreview.speciesId;
            changed = true;
          }

          if (changed) {
            const previewForm = colorSelect.closest('form');
            if (previewForm) previewForm.submit();
          }

          const savePrefs = () => {
            savedPreview = {
              colorId: colorSelect.value,
              speciesId: speciesSelect.value
            };
            writeJSON(PREVIEW_KEY, savedPreview);
          };

          colorSelect.addEventListener('change', savePrefs);
          speciesSelect.addEventListener('change', savePrefs);

          return true;
        };

