            const STAGING_FMT_KEY = 'dia_staging_fmt_v4';
            const STAGING_CASE_KEY = 'dia_staging_case_v4';
            const lsGet = (k, d) => { try { const v = localStorage.getItem(k); return v !== null ? JSON.parse(v) : d; } catch(_) { return d; } };
            const lsSet = (k, v) => { try { localStorage.setItem(k, JSON.stringify(v)); } catch(_) {} };

