            const fmt = (items, side) => {

              const applyCase = str => pasteCase === 'lower' ? str.toLowerCase() : str;
              const entries = items.filter(item => (item.qty ?? 1) > 0).map(item => {
                const q = item.qty ?? 1;
                const prefix      = q > 1 ? q + 'x ' : '';
                const eaSuffix    = q > 1 ? ' ea' : '';
                const valueSuffix = includeValues && item.value ? ` (${item.value}${eaSuffix})` : '';
                return applyCase(prefix + item.name) + valueSuffix;
              });
              if (pasteFormat === 'csv')     return entries.join(', ');
              if (pasteFormat === 'plus')    return entries.join(' + ');
              if (pasteFormat === 'bullets') return entries.map(e => '• ' + e).join('\n');
              return entries.join('\n');
            };

            const TRASH_SVG = '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style="display:block;pointer-events:none;"><path d="M4 7h16M9 7V5.5A1.5 1.5 0 0 1 10.5 4h3A1.5 1.5 0 0 1 15 5.5V7M6.5 7.5l.7 10.5a2 2 0 0 0 2 1.9h5.6a2 2 0 0 0 2-1.9l.7-10.5M10 11.5v4M14 11.5v4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>';
            const COPY_BTN_SVG = '<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" style="display:block;"><rect x="5" y="1" width="9" height="9" rx="2" stroke="currentColor" stroke-width="1.5"/><path d="M3 5H2.5A1.5 1.5 0 0 0 1 6.5v7A1.5 1.5 0 0 0 2.5 15h7A1.5 1.5 0 0 0 11 13.5V13" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>';
            const copyText = (text, btn) => {
              navigator.clipboard.writeText(text).then(() => {
                btn.innerHTML = '✓';
                setTimeout(() => { btn.innerHTML = COPY_BTN_SVG; }, 1500);
              });
            };

            const parseCaps = val => {
              if (!val) return null;
              const clean = String(val).replace(/[^0-9\-]/g, '').trim();
              const parts = clean.split('-').map(Number).filter(n => !isNaN(n) && n > 0 && n < 1000);
              return parts.length ? { lo: parts[0], hi: parts[parts.length - 1] } : null;
            };

            const colCaps = side => {
              let lo = 0, hi = 0, hasBlanks = false;
              stagingData[side].forEach(i => {
                if (!i) return;
                const q = i.qty ?? 1;
                if (q === 0) return;
                const c = parseCaps(i.value);
                if (!c) { hasBlanks = true; }
                else { lo += c.lo * q; hi += c.hi * q; }
              });
              return { lo, hi, hasBlanks };
            };
            const fmtCaps = side => {
              const { lo, hi, hasBlanks } = colCaps(side);
              if (!lo && !hi) return '';
              const range = lo === hi ? `${lo}` : `${lo}–${hi}`;
              return range + (hasBlanks ? '*' : '') + (lo === hi && lo === 1 ? ' cap' : ' caps');
            };

